import { useState } from "react";
import { KanbanBoard } from "../../components/kanban/KanbanBoard";
import { boardConfig } from "./config";
import { initialCards } from "./data";
import { useReusableCardRendererBoardCardChange, useReusableCardRendererBoardLoadMore } from "./useCardChange";
import type { KanbanCardData } from "./types";

/**
 * Reusable Card Renderer
 * config.renderCard — applied to every card
 *
 * Drag-and-drop is powered by the project's custom Pointer DnD library
 * (no @dnd-kit dependency). Cards persist locally — wire `useCardChange`
 * to your backend to make moves stick across reloads.
 */
export default function ReusableCardRendererBoard() {
  const [cards, setCards] = useState<KanbanCardData[]>(initialCards);
  const handleCardChange = useReusableCardRendererBoardCardChange();
  const handleLoadMore = useReusableCardRendererBoardLoadMore();
  return (
    <div className="space-y-4">
      <div>
        <h2 className="text-xl font-bold">{boardConfig.title}</h2>
        {boardConfig.subtitle && (
          <p className="text-sm text-muted-foreground">{boardConfig.subtitle}</p>
        )}
      </div>
      <KanbanBoard
        config={boardConfig}
        cards={cards}
        onCardsChange={setCards}
        onCardChange={handleCardChange}
        onLoadMore={handleLoadMore}
      />
    </div>
  );
}

import { AlertTriangle } from "lucide-react";
import type { CardRenderer } from "../../components/kanban/types";

/**
 * Case 1 — single reusable renderer. Every card renders through this body
 * unless it defines its own `card.render`. Return undefined to fall through
 * to the built-in <KanbanCard />.
 */
export const renderCard: CardRenderer = ({ card }) => {
  if (card.priority !== "urgent") return undefined;
  return (
    <div className="rounded-md border-2 border-destructive bg-destructive/5 p-3 text-sm">
      <div className="mb-1 flex items-center gap-1.5 text-[10px] font-semibold uppercase tracking-wider text-destructive">
        <AlertTriangle className="h-3 w-3" />
        Urgent
      </div>
      <div className="font-medium leading-tight">{card.title}</div>
      {card.assignee && (
        <div className="mt-2 text-[11px] text-muted-foreground">@{card.assignee}</div>
      )}
    </div>
  );
};

import type { KanbanBuilderConfig } from "./types";
import { renderCard } from "./renderers";

