 * Static configuration. The single reusable `renderCard` lives in ./renderers.tsx.
 *
 * Resolution order at render time:
 *   card.render   ->   config.renderCard   ->   built-in <KanbanCard />
 */
export const boardConfig: KanbanBuilderConfig = {
  "title": "Reusable Card Renderer",
  "subtitle": "config.renderCard — applied to every card",
  "layout": "board",
  "columns": [
    {
      "id": "todo",
      "title": "To Do",
      "color": "amber"
    },
    {
      "id": "doing",
      "title": "Doing",
      "color": "blue"
    },
    {
      "id": "done",
      "title": "Done",
      "color": "emerald"
    }
  ],
  "visibleFields": [
    "priority",
    "assignee"
  ],
  "enableDnd": true,
  "enableAddCard": true,
  "enableWipLimits": false,
  "showColumnTotals": true,
  "compactCards": false,
  renderCard,
};

import type { KanbanCardData } from "./types";

